settings.custom_liquid:
{% style %}
  .card-wrapper:hover .media.media--hover-effect > img + img {
    transition: none!important;
  }
.pagination__item {
font-size: 1.2rem!important;
}
.card-information {
text-align:center!important;
}
    .badge {
color: #000000BF!important;
font-size:1.2rem!important;
}
#shopify-section-template--21415098843453__main h1 {
    font-size: 0px;
    display: none!important;
}
#shopify-section-template--21415098319165__product-grid .h5 {
    font-size: calc(var(--font-heading-scale) * 1.15rem);
    font-family: 'Helvetica';
    color: #000000BF!important;
}
.card--standard>.card__content .card__information {
text-align: center!important;
}
#shopify-section-template--21415098319165__product-grid .price {
    font-size: 1.15rem;
    font-family: "Arial";
    letter-spacing: 0.1rem;
    line-height: calc(1 + 0 / var(--font-body-scale));
    color: #000000BF!important;
    text-align: center;
}

/* label of sort by */
.facet-filters__label{
font-size: 1.2rem;
font-weight: 300;
}

/* sort by options */
.facet-filters__sort{
font-size: 1.2rem;
font-family: "Arial";

}

/* filter label */
.facets__heading{
font-size: 1.2rem;
font-weight: 300;
font-family: "Arial";

}

/* filter titles */
.facets__summary {
font-size: 1.2rem;
font-family: "Arial";

}

/* text inside checkboxes */
.facet-checkbox{
font-size: 1.2rem;
font-family: "Arial";

}
.product-count__text {
    font-size: 1.2rem;
    line-height: calc(1 + .5 / var(--font-body-scale));
    color: black;
font-family: "Arial";
    margin: 0;
}
@media screen and (max-width: 989px) {
.section-template--21415098319165__product-grid-padding {
    padding-top: 0px!important; 
    padding-bottom: 27px;
}
.facets-container {
    padding-top: 0!important;
}
.pd_20 {
    padding-top: 0px!important;
}
}
@media screen and (min-width: 990px){
.facets-container-drawer {
    display: flex;
    flex-flow: row wrap;
    align-items: center;
    column-gap: 0;
    margin: 0 7rem!important;
}
.grid--4-col-desktop .grid__item {
    width: calc(23% - var(--grid-desktop-horizontal-spacing) * 3 / 4);
    max-width: calc(23% - var(--grid-desktop-horizontal-spacing) * 3 / 4);
}
.grid {
    column-gap: var(--grid-desktop-horizontal-spacing);
    row-gap: var(--grid-desktop-vertical-spacing);
 column-gap: 3rem!important; 
margin-left: 7.5rem!important; }
.facets-container-drawer {
    display: flex;
    flex-flow: row wrap;
    align-items: center;
    column-gap: 0;
    margin: 0 5rem;
}}
@media screen and (min-width: 1200px) {
.grid {
    column-gap: var(--grid-desktop-horizontal-spacing);
    row-gap: var(--grid-desktop-vertical-spacing);
    column-gap: 4rem!important;
    margin-left: 6.5rem!important;
}
}
@media screen and (min-width: 1300px) {
.grid {
    column-gap: var(--grid-desktop-horizontal-spacing);
    row-gap: var(--grid-desktop-vertical-spacing);
    column-gap: 5rem!important;
    margin-left: 5.5rem!important;
}
}
element.style {
}
.badge {
    border: none; 
    border-radius: var(--badge-corner-radius);
    display: inline-block;
    font-size: 1.2rem;
    letter-spacing: 0.05rem;
    line-height: 1;
    padding: 0.3rem 1rem 0.6rem 1rem;
    text-align: center;
    background-color: transparent;
    /* border-color: rgba(var(--color-badge-border), var(--alpha-badge-border)); */
    color: black;
    word-break: break-word;
}

@media screen and (max-width: 767px){
.card--standard>.card__content .card__information {
    padding-left: 0;
    padding-right: 0;
    margin: 0 auto;

}

#shopify-section-template--21415098319165__product-grid .h5 {
    font-size: calc(var(--font-heading-scale) * 1.5rem);
color: #000000BF!important;
}
#shopify-section-template--21415098319165__product-grid .price {
    font-size: 1.5rem;
    font-family: "Arial";
    letter-spacing: 0.1rem;
    line-height: calc(1 + 0 / var(--font-body-scale));
    color: rgb(var(--color-foreground));
}

}


{% endstyle %}
